(function($){'use strict';const GHLMenuEditor={init:function(){const self=this;self.initializeAllSelect2();$(document).on('change','.ghl-visibility-rule-select',function(){const $menuItem=$(this).closest('.menu-item');self.updateTagFieldVisibility($menuItem)});$('.ghl-visibility-rule-select').each(function(){const $menuItem=$(this).closest('.menu-item');self.updateTagFieldVisibility($menuItem)});$(document).on('click','.item-edit',function(){setTimeout(function(){self.initializeAllSelect2()},100)})},initializeAllSelect2:function(){const self=this;$('.ghl-tags-select').each(function(){const $tagSelect=$(this);if($tagSelect.data('select2')){return}
const $section=$tagSelect.closest('.ghl-menu-visibility-section');let savedTags=$section.data('saved-tags')||[];const tagNamesMap=$section.data('tag-names')||{};if(typeof savedTags==='object'&&!Array.isArray(savedTags)){savedTags=Object.values(savedTags).filter(function(tag){return tag&&tag.trim()!==''})}
if(!Array.isArray(savedTags)){savedTags=[]}
var allTags=(typeof ghlMenuEditor!=='undefined'&&ghlMenuEditor.tags)?ghlMenuEditor.tags:[];allTags.forEach(function(tag){var tagId=String(tag.id||tag.name||'');var tagName=String(tag.name||tag.id||'');if(tagId&&!$tagSelect[0].querySelector('option[value="'+CSS.escape(tagId)+'"]')){$tagSelect.append(new Option(tagName,tagId,!1,!1))}});$tagSelect.select2({tags:!0,tokenSeparators:[','],placeholder:(typeof ghlMenuEditor!=='undefined'&&ghlMenuEditor.strings)?ghlMenuEditor.strings.searchTags:'Search tags...',allowClear:!0,width:'100%',minimumInputLength:0});if(savedTags.length>0){savedTags.forEach(function(tagId){if(tagId&&tagId.trim()!==''){const tagName=tagNamesMap[tagId]||tagId;const option=new Option(tagName,tagId,!0,!0);$tagSelect.append(option)}});$tagSelect.trigger('change')}})},updateTagFieldVisibility:function($menuItem){const $ruleSelect=$menuItem.find('.ghl-visibility-rule-select');const $tagsField=$menuItem.find('.ghl-tags-field');const rule=$ruleSelect.val();const showTags=['has_any_tag','has_all_tags','not_has_tags'].includes(rule);if(showTags){$tagsField.show()}else{$tagsField.hide()}}};$(document).ready(function(){GHLMenuEditor.init()})})(jQuery)